mapper.select:
/* selectAdmin501List */ SELECT ts.srvy_oid, ts.srvy_ttl, ts.srvy_bgng_dt, ts.srvy_end_dt, ts.srvy_type, tc2.cd_nm AS srvy_type_nm ,ts.srvy_trgt, tc.cd_nm AS srvyTgtNm , tc1.cd_nm AS srvy_stts, ts.nm_clct_yn, ts.gndr_clct_yn, ts.inst_clct_yn , ts.mpno_clct_yn, ts.eml_clct_yn, ts.addr_clct_yn , ts.srvy_cn, ts.atch_file_use_yn, ts.atch1_file_ttl, ts.atch1_file_oid , ts.atch2_file_ttl, ts.atch2_file_oid , ts.rspns_cnt, ts.reg_id, ts.reg_dt, ts.mdfcn_id, ts.mdfcn_dt FROM ${schema}.srvy ts LEFT JOIN ${schema}.grp_cd tgc ON tgc.grp_cd = 'survey_tgt' AND tgc.use_yn = 'Y' LEFT JOIN ${schema}.cd tc ON tc.grp_cd_oid = tgc.grp_cd_oid AND tc.cd_val = ts.srvy_trgt AND tc.use_yn = 'Y' LEFT JOIN ${schema}.grp_cd tgc1 ON tgc1.grp_cd = 'survey_stat' AND tgc1.use_yn = 'Y' LEFT JOIN ${schema}.cd tc1 ON tc1.grp_cd_oid = tgc1.grp_cd_oid AND tc1.cd_val = ts.srvy_stts AND tc1.use_yn = 'Y' LEFT JOIN ${schema}.grp_cd tgc2 ON tgc2.grp_cd = 'survey_type' AND tgc2.use_yn = 'Y' LEFT JOIN ${schema}.cd tc2 ON tc2.grp_cd_oid = tgc2.grp_cd_oid AND tc2.cd_val = ts.srvy_type AND tc2.use_yn = 'Y'
ts.srvy_stts <> 'DEL'
AND ts.srvy_oid = #{srvyOid}
AND ts.srvy_ttl like CONCAT('%',#{srvyTtl},'%')
AND ts.srvy_stts = #{srvyStts}
AND ts.reg_dt >= CONCAT(#{srvyBgngDt}, ' 23:59:59')
AND ts.reg_dt <= CONCAT(#{surveyEndtDt}, ' 23:59:59')
AND ts.reg_dt >= CONCAT(#{regStartDt}, ' 23:59:59')
AND ts.reg_dt <= CONCAT(#{regEndDt}, ' 23:59:59')
AND ts.srvy_type = #{srvyType}
ORDER BY srvy_oid DESC

/* selectAdmin501Detail */ SELECT srvy_oid, srvy_ttl, srvy_bgng_dt, srvy_end_dt, srvy_type , srvy_trgt, nm_clct_yn, gndr_clct_yn, inst_clct_yn , mpno_clct_yn, eml_clct_yn, addr_clct_yn , srvy_cn, atch_file_use_yn, atch1_file_ttl, atch1_file_oid , atch2_file_ttl, atch2_file_oid , CASE WHEN srvy_stts = 'DEL' THEN '미사용' ELSE '사용' END AS srvy_stts , rspns_cnt, reg_id, reg_dt, mdfcn_id, mdfcn_dt FROM ${schema}.srvy
AND srvy_oid = #{srvyOid}
ORDER BY srvy_oid DESC

/* selectAdmin501OptList */ SELECT srvy_qitem_opt_oid, srvy_qitem_oid, srvy_qitem_opt_seq, srvy_qitem_opt_txt , srvy_qitem_opt_img_file_oid, etc_opt_yn, rspns_cnt , reg_id, reg_dt, mdfcn_id, mdfcn_dt FROM ${schema}.srvy_qitem_opt WHERE srvy_qitem_oid IN
#{srvyQitemOid}
ORDER BY srvy_qitem_opt_seq

mapper.insert:
	/* insertAdmin501Survey */
	INSERT INTO ${schema}.srvy(
          srvy_ttl, srvy_bgng_dt, srvy_end_dt, srvy_trgt, srvy_type
        , srvy_cn, nm_clct_yn, gndr_clct_yn
        , inst_clct_yn, mpno_clct_yn
        , eml_clct_yn, addr_clct_yn
        , srvy_stts, reg_id, reg_dt, mdfcn_id, mdfcn_dt
    )
    VALUES (
          #{srvyTtl}, #{srvyBgngDt}, #{srvyEndDt}, #{srvyTrgt}, #{srvyType}
        , #{srvyCn} , #{nmClctYn} , #{gndrClctYn}
        , #{instClctYn}, #{mpnoClctYn}
        , #{emlClctYn}, #{addrClctYn}
	    , #{srvyStts}, #{regId}, NOW(),#{mdfcnId}, NOW()
    )

/* insertAdmin501SurveyQst */
INSERT INTO ${schema}.srvy_qitem (
      srvy_oid , up_srvy_qitem_oid , srvy_qitem_seq
    , srvy_qitem_ttl , srvy_qitem_type , esntl_yn , plrl_chc_yn
    , lmt_yn , srvy_qitem_lmt , etc_add_yn , likert_min
    , likert_max , likert_min_lbl , likert_max_lbl
    , reg_id , reg_dt, mdfcn_id , mdfcn_dt
)
VALUES (
      #{srvyOid}, #{upSrvyQitemOid}, #{srvyQitemSeq}
    , #{srvyQitemTtl}, #{srvyQitemType}, #{esntlYn}, #{plrlChcYn}
    , #{lmtYn}, #{srvyQitemLmt}, #{etcAddYn}, #{likertMin}
    , #{likertMax}, #{likertMinLbl}, #{likertMaxLbl}
    , #{regId}, NOW(), #{mdfcnId}, NOW()
)

/* insertAdmin501SurveyOpt */
INSERT INTO ${schema}.srvy_qitem_opt (
      srvy_qitem_oid , srvy_qitem_opt_seq , srvy_qitem_opt_txt
    , srvy_qitem_opt_img_file_oid, etc_opt_yn
    , reg_id, reg_dt, mdfcn_id, mdfcn_dt
)
VALUES (
      #{srvyQitemOid}, #{srvyQitemOptSeq}, #{srvyQitemOptTxt}
    , #{srvyQitemOptImgFileOid}, #{etcOptYn}
    , #{regId}, NOW(), #{mdfcnId}, NOW()
)

/* insertSurveyCopy */ INSERT INTO ${schema}.srvy ( srvy_ttl , srvy_bgng_dt, srvy_end_dt , srvy_type , srvy_trgt, nm_clct_yn, gndr_clct_yn , inst_clct_yn, mpno_clct_yn, eml_clct_yn , addr_clct_yn, srvy_cn, atch_file_use_yn , atch1_file_ttl, atch1_file_oid , atch2_file_ttl, atch2_file_oid , srvy_stts , reg_id, reg_dt ) SELECT #{newSrvyTtl} ,
#{srvyBgngDt}
srvy_bgng_dt
,
#{srvyEndDt}
srvy_end_dt
, srvy_type , srvy_trgt, nm_clct_yn, gndr_clct_yn , inst_clct_yn, mpno_clct_yn, eml_clct_yn , addr_clct_yn, srvy_cn, atch_file_use_yn , atch1_file_ttl, atch1_file_oid , atch2_file_ttl, atch2_file_oid , 'PROG' , #{userId}, NOW() FROM ${schema}.srvy WHERE srvy_oid = #{oldSrvyOid}

mapper.update:
/* updateParentQst */
UPDATE ${schema}.srvy_qitem
SET up_srvy_qitem_oid = #{upSrvyQitemOid}
WHERE srvy_qitem_oid = #{srvyQitemOid}

/* updateAdmin501Stat */
UPDATE ${schema}.srvy
	SET srvy_stts = #{srvyStts}
		, mdfcn_id = #{mdfcnId}
		, mdfcn_dt = now()
WHERE
	srvy_oid = #{srvyOid}

